const COMMON_HEIGHTS = [
  64, 100, 128, 150, 200, 250, 256, 300, 350, 400, 450, 500,
  512, 550, 600, 650, 700, 750, 800, 850, 900, 950, 1000
];

const PixelatorModal: React.FC<PixelatorModalProps> = ({ isOpen, onClose, layer }) => {
  const updateLayer = useCompositorStore((state) => state.updateLayer);
  const layers = useCompositorStore((state) => state.project.layers);
  const cropCanvasToLayers = useCompositorStore((state) => state.cropCanvasToLayers);
  const isPortrait = usePortraitMode();

  // State
  const [targetHeight, setTargetHeight] = useState<number>(128);
  const [originalHeight, setOriginalHeight] = useState<number>(128);
  const [resamplingMethod, setResamplingMethod] = useState<'nearest' | 'bilinear' | 'lanczos' | 'pixeloe-nearest' | 'pixeloe-contrast' | 'pixeloe-k-centroid'>('bilinear');
  const [ditherMethod, setDitherMethod] = useState<string>('none');
  const [ditherStrength, setDitherStrength] = useState<number>(100);
  const [preprocessingMethod, setPreprocessingMethod] = useState<'none' | 'bilateral' | 'kuwahara' | 'median' | 'edge-detect'>('none');
  const [preprocessingStrength, setPreprocessingStrength] = useState<number>(50);
  const [paletteMode, setPaletteMode] = useState<'geopixels' | 'wplace' | 'wplace-free' | 'custom' | 'geopixels+custom' | 'preset' | 'none'>('preset');
  const [customPaletteInput, setCustomPaletteInput] = useState<string>('');
  const [selectedPreset, setSelectedPreset] = useState<string>('Geopixels Base');
  const [includeGeopixelsBase, setIncludeGeopixelsBase] = useState<boolean>(true);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [resultDimensions, setResultDimensions] = useState<{ width: number; height: number } | null>(null);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [zoom, setZoom] = useState<number>(1);
  const [imageDimensions, setImageDimensions] = useState<{ width: number; height: number } | null>(null);
  const [displayHeight, setDisplayHeight] = useState(String(targetHeight));
  const [isPaletteVisualizationOpen, setIsPaletteVisualizationOpen] = useState(true);
  const [useKmeans, setUseKmeans] = useState<boolean>(false);
  const [kmeansColors, setKmeansColors] = useState<number>(16);
  const [suggestedColors, setSuggestedColors] = useState<string[]>([]);
  const [suggestCount, setSuggestCount] = useState<number>(8);
  const [isSuggesting, setIsSuggesting] = useState<boolean>(false);
  const [preferDistinctColors, setPreferDistinctColors] = useState<boolean>(true);
  const [hasSemiTransparent, setHasSemiTransparent] = useState<boolean>(false);
  const [autoUpdate, setAutoUpdate] = useState<boolean>(true);
  const [colorStats, setColorStats] = useState<Map<string, { count: number, percent: number }>>(new Map());
  const [hoveredColor, setHoveredColor] = useState<string | null>(null);
  const [hoverPos, setHoverPos] = useState<{ x: number, y: number } | null>(null);
  const [generatedPalette, setGeneratedPalette] = useState<string[]>([]);
  const [hasInitialFit, setHasInitialFit] = useState<boolean>(false);
  const [pinFitToScreen, setPinFitToScreen] = useState<boolean>(true);
  const [filterTrivialColors, setFilterTrivialColors] = useState<boolean>(false);
  const [trivialThreshold, setTrivialThreshold] = useState<number>(0.1);
  const [displayTrivialThreshold, setDisplayTrivialThreshold] = useState<string>('0.1');
  const [trivialThresholdMode, setTrivialThresholdMode] = useState<'percent' | 'pixels'>('percent');

  // Before/After comparison slider (0 = all original, 100 = all pixelated)
  const [comparePosition, setComparePosition] = useState<number>(100);

  // Extra Features State
  const [isExtraFeaturesOpen, setIsExtraFeaturesOpen] = useState<boolean>(false);
  const [brightness, setBrightness] = useState<number>(0);
  const [contrast, setContrast] = useState<number>(0);
  const [saturation, setSaturation] = useState<number>(0);
  const [colorMatchAlgorithm, setColorMatchAlgorithm] = useState<string>('oklab');
  const [preserveDetailThreshold, setPreserveDetailThreshold] = useState<number>(0);

  // PixelOE settings
  const [pixeloeThickness, setPixeloeThickness] = useState<number>(2);
  const [pixeloePatchSize, setPixeloePatchSize] = useState<number>(16);

  // Edge detection settings
  const [edgeDetectBlur, setEdgeDetectBlur] = useState<number>(0);
  const [edgeDetectAlgorithm, setEdgeDetectAlgorithm] = useState<'sobel' | 'scharr' | 'laplacian'>('sobel');

  // Context menu state for palette swatches
  const [contextMenu, setContextMenu] = useState<{ x: number; y: number; color: string; editing?: boolean; editValue?: string } | null>(null);

  // Highlight color on the preview canvas
  const [highlightColor, setHighlightColor] = useState<string | null>(null);
  const highlightCanvasRef = useRef<HTMLCanvasElement>(null);
  const previewImageDataRef = useRef<ImageData | null>(null);

  // Eyedropper modal state
  const [isEyedropperOpen, setIsEyedropperOpen] = useState<boolean>(false);

  // GeoPixels palette modal state
  const [isGeoPixelsPaletteOpen, setIsGeoPixelsPaletteOpen] = useState<boolean>(false);

  // Gradient picker modal state
  const [isGradientPickerOpen, setIsGradientPickerOpen] = useState<boolean>(false);

  // Group noise modal state
  const [isGroupNoiseOpen, setIsGroupNoiseOpen] = useState<boolean>(false);

  // Sampling mask state
  const [samplingMaskEnabled, setSamplingMaskEnabled] = useState<boolean>(false);
  const [samplingMask, setSamplingMask] = useState<Uint8Array | null>(null);
  const [samplingMaskDims, setSamplingMaskDims] = useState<{ w: number; h: number } | null>(null);
  const [isSamplingMaskModalOpen, setIsSamplingMaskModalOpen] = useState<boolean>(false);

  // Presets state
  const [isPresetsModalOpen, setIsPresetsModalOpen] = useState<boolean>(false);
  const [presets, setPresets] = useState<{ name: string; settings: Record<string, any> }[]>([]);
  const [presetName, setPresetName] = useState<string>('');

  const workerRef = useRef<Worker | null>(null);
  const previewContainerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);
  const originalImgRef = useRef<HTMLImageElement>(null);
  const compareContainerRef = useRef<HTMLDivElement>(null);
  const isDraggingCompare = useRef<boolean>(false);
  const jobIdRef = useRef<number>(0);
  const [settingsLoaded, setSettingsLoaded] = useState<boolean>(false);

  // Track previous state to restore K-Means when switching back to 'none'
  const wasKmeansEnabledRef = useRef<boolean>(false);
  const prevPaletteModeRef = useRef<string>(paletteMode);
  const debounceTimeRef = useRef<number>(750);

  const analyzePreviewColors = (imageData: ImageData) => {
    previewImageDataRef.current = imageData;
    const data = imageData.data;
    const stats = new Map<string, number>();
    let totalPixels = 0;

    for (let i = 0; i < data.length; i += 4) {
      const r = data[i];
      const g = data[i + 1];
      const b = data[i + 2];
      const a = data[i + 3];

      if (a === 0) continue; // Skip transparent

      // Convert to hex
      const hex = `#${((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1).toUpperCase()}`;
      stats.set(hex, (stats.get(hex) || 0) + 1);
      totalPixels++;
    }

    const result = new Map<string, { count: number, percent: number }>();
    stats.forEach((count, hex) => {
      result.set(hex, {
        count,
        percent: totalPixels > 0 ? (count / totalPixels) * 100 : 0
      });
    });

    setColorStats(result);
  };

  // Helper to (re)create worker with message handler
  const createWorker = useCallback(() => {
    workerRef.current?.terminate();
    const w = new PixelatorWorker();
    w.onmessage = (e) => {
      const { type, imageData, message, suggestions, generatedPalette } = e.data;
      if (type === 'success') {
        const canvas = document.createElement('canvas');
        canvas.width = imageData.width;
        canvas.height = imageData.height;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.putImageData(imageData, 0, 0);
          setImageDimensions({ width: imageData.width, height: imageData.height });
          setResultDimensions({ width: imageData.width, height: imageData.height });
          if (pinFitToScreen) {
            const newZoom = calculateFitZoom(imageData.width, imageData.height);
            setZoom(newZoom);
          }
          setPreviewImage(canvas.toDataURL());
          analyzePreviewColors(imageData);
          if (generatedPalette) {
            setGeneratedPalette(generatedPalette);
          } else {
            setGeneratedPalette([]);
          }
        }
      } else if (type === 'suggestions') {
        setSuggestedColors(suggestions);
        setIsSuggesting(false);
      } else {
        console.error('Pixelator Worker Error:', message);
        setIsSuggesting(false);
      }
      setIsProcessing(false);
    };
    workerRef.current = w;
    return w;
  }, [pinFitToScreen]);

  // Initialize Worker
  useEffect(() => {
    createWorker();
    return () => {
      workerRef.current?.terminate();
    };
  }, [createWorker]);

  // Sync display height when targetHeight changes
  useEffect(() => {
    setDisplayHeight(String(targetHeight));
  }, [targetHeight]);

  // Load cached custom palette on mount
  useEffect(() => {
    const cached = localStorage.getItem('pixelator_custom_palette');
    if (cached) {
      setCustomPaletteInput(cached);
    }
  }, []);

  // Load persisted settings on mount
  useEffect(() => {
    try {
      const raw = localStorage.getItem('pixelator_settings');
      if (raw) {
        const s = JSON.parse(raw);
        if (s.targetHeight != null) setTargetHeight(s.targetHeight);
        if (s.resamplingMethod) setResamplingMethod(s.resamplingMethod);
        if (s.ditherMethod) setDitherMethod(s.ditherMethod);
        if (s.ditherStrength != null) setDitherStrength(s.ditherStrength);
        if (s.preprocessingMethod) setPreprocessingMethod(s.preprocessingMethod);
        if (s.preprocessingStrength != null) setPreprocessingStrength(s.preprocessingStrength);
        if (s.paletteMode) {
          // Migrate old geopixels+custom to custom
          setPaletteMode(s.paletteMode === 'geopixels+custom' ? 'custom' : s.paletteMode);
        }
        if (s.includeGeopixelsBase != null) setIncludeGeopixelsBase(s.includeGeopixelsBase);
        else if (s.paletteMode === 'geopixels+custom') setIncludeGeopixelsBase(true);
        if (s.selectedPreset != null) setSelectedPreset(s.selectedPreset);
        if (s.useKmeans != null) setUseKmeans(s.useKmeans);
        if (s.kmeansColors != null) setKmeansColors(s.kmeansColors);
        if (s.brightness != null) setBrightness(s.brightness);
        if (s.contrast != null) setContrast(s.contrast);
        if (s.saturation != null) setSaturation(s.saturation);
        if (s.colorMatchAlgorithm) setColorMatchAlgorithm(s.colorMatchAlgorithm);
        if (s.preserveDetailThreshold != null) setPreserveDetailThreshold(s.preserveDetailThreshold);
        if (s.filterTrivialColors != null) setFilterTrivialColors(s.filterTrivialColors);
        if (s.trivialThreshold != null) { setTrivialThreshold(s.trivialThreshold); setDisplayTrivialThreshold(String(s.trivialThreshold)); }
        if (s.trivialThresholdMode) setTrivialThresholdMode(s.trivialThresholdMode);
        if (s.pixeloeThickness != null) setPixeloeThickness(s.pixeloeThickness);
        if (s.pixeloePatchSize != null) setPixeloePatchSize(s.pixeloePatchSize);
        if (s.edgeDetectBlur != null) setEdgeDetectBlur(s.edgeDetectBlur);
        if (s.edgeDetectAlgorithm) setEdgeDetectAlgorithm(s.edgeDetectAlgorithm);
        if (s.autoUpdate != null) setAutoUpdate(s.autoUpdate);
        if (s.isPaletteVisualizationOpen != null) setIsPaletteVisualizationOpen(s.isPaletteVisualizationOpen);
        if (s.isExtraFeaturesOpen != null) setIsExtraFeaturesOpen(s.isExtraFeaturesOpen);
      }
    } catch { /* ignore corrupt data */ }
    // Load presets
    try {
      const rawPresets = localStorage.getItem('pixelator_presets');
      if (rawPresets) setPresets(JSON.parse(rawPresets));
    } catch { /* ignore */ }
    setSettingsLoaded(true);
  }, []);

  // Save settings to localStorage whenever they change
  const settingsToSave = useMemo(() => ({
    targetHeight, resamplingMethod, ditherMethod, ditherStrength,
    preprocessingMethod, preprocessingStrength, paletteMode,
    useKmeans, kmeansColors, brightness, contrast, saturation,
    colorMatchAlgorithm, preserveDetailThreshold,
    filterTrivialColors, trivialThreshold, trivialThresholdMode,
    pixeloeThickness, pixeloePatchSize, edgeDetectBlur, edgeDetectAlgorithm,
    autoUpdate, isPaletteVisualizationOpen, isExtraFeaturesOpen, includeGeopixelsBase, selectedPreset,
  }), [targetHeight, resamplingMethod, ditherMethod, ditherStrength,
    preprocessingMethod, preprocessingStrength, paletteMode,
    useKmeans, kmeansColors, brightness, contrast, saturation,
    colorMatchAlgorithm, preserveDetailThreshold,
    filterTrivialColors, trivialThreshold, trivialThresholdMode,
    pixeloeThickness, pixeloePatchSize, edgeDetectBlur, edgeDetectAlgorithm,
    autoUpdate, isPaletteVisualizationOpen, isExtraFeaturesOpen, includeGeopixelsBase, selectedPreset]);

  useEffect(() => {
    if (!settingsLoaded) return;
    localStorage.setItem('pixelator_settings', JSON.stringify(settingsToSave));
  }, [settingsToSave, settingsLoaded]);

  // Initialize original height from layer dimensions
  useEffect(() => {
    if (isOpen && layer.imageData) {
      const img = new Image();
      img.onload = () => {
        setOriginalHeight(img.height);
      };
      img.src = layer.imageData;
    }
  }, [isOpen, layer.imageData]);

  // Save custom palette to localStorage on change
  useEffect(() => {
    if (customPaletteInput.trim()) {
      localStorage.setItem('pixelator_custom_palette', customPaletteInput);
    }
  }, [customPaletteInput]);

  // Helper to parse custom palette
  const getPalette = useCallback(() => {
    if (paletteMode === 'none') return [];
    if (paletteMode === 'geopixels') return GEOPIXELS_PALETTE;
    if (paletteMode === 'wplace') return WPLACE_PALETTE;
    if (paletteMode === 'wplace-free') return WPLACE_FREE_PALETTE;

    // Parse custom input
    const rawInput = customPaletteInput.trim();
    let customColors: string[] = [];

    if (rawInput) {
      // Split by comma, space, or newline to handle various formats
      const parts = rawInput.split(/[\s,]+/).filter(s => s.trim() !== '');

      customColors = parts.map(s => {
        const trimmed = s.trim();

        // Check if it's a decimal integer (e.g. "16777215")
        if (/^\d+$/.test(trimmed)) {
          const decimal = parseInt(trimmed, 10);
          // Ensure it's a valid 24-bit color
          if (decimal >= 0 && decimal <= 16777215) {
            return '#' + decimal.toString(16).padStart(6, '0').toUpperCase();
          }
        }

        // Check if it's a hex code (e.g. "#FFFFFF" or "FFFFFF")
        if (/^#?[0-9A-F]{6}$/i.test(trimmed)) {
          return trimmed.startsWith('#') ? trimmed.toUpperCase() : '#' + trimmed.toUpperCase();
        }

        return null;
      }).filter((c): c is string => c !== null);
    }

    if (paletteMode === 'preset') {
      const found = PRESET_PALETTES.find(p => p.label === selectedPreset);
      return found ? found.palette : [];
    }
    if (paletteMode === 'custom') {
      if (includeGeopixelsBase) {
        const merged = [...GEOPIXELS_PALETTE];
        for (const color of customColors) {
          if (!merged.includes(color.toUpperCase())) merged.push(color.toUpperCase());
        }
        return merged;
      }
      return customColors;
    }
    // Backward compat: old saved settings with geopixels+custom
    if (paletteMode === 'geopixels+custom') {
      const merged = [...GEOPIXELS_PALETTE];
      for (const color of customColors) {
        if (!merged.includes(color.toUpperCase())) merged.push(color.toUpperCase());
      }
      return merged;
    }

    return [];
  }, [paletteMode, customPaletteInput, selectedPreset, includeGeopixelsBase]);

  // Handle K-Means state when palette mode changes
  useEffect(() => {
    // Leaving 'none' mode
    if (prevPaletteModeRef.current === 'none' && paletteMode !== 'none') {
      if (useKmeans) {
        wasKmeansEnabledRef.current = true;
        setUseKmeans(false);
      } else {
        wasKmeansEnabledRef.current = false;
      }
    }
    // Entering 'none' mode
    else if (prevPaletteModeRef.current !== 'none' && paletteMode === 'none') {
      if (wasKmeansEnabledRef.current) {
        setUseKmeans(true);
      }
    }
    // Ensure K-Means is off if not in 'none' mode (cleanup/safety)
    else if (paletteMode !== 'none' && useKmeans) {
      setUseKmeans(false);
    }

    prevPaletteModeRef.current = paletteMode;
  }, [paletteMode, useKmeans]);

  // Trigger Processing
  const processImage = useCallback(() => {
    if (!layer.imageData) return;

    // Cancel any in-flight worker job by terminating and recreating
    createWorker();
    const currentJobId = ++jobIdRef.current;

    setIsProcessing(true);

    // Load image to get ImageData
    const img = new Image();
    img.onload = () => {
      // If another processImage call happened while loading, bail out
      if (currentJobId !== jobIdRef.current) return;

      const canvas = document.createElement('canvas');
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      ctx.drawImage(img, 0, 0);
      const imageData = ctx.getImageData(0, 0, img.width, img.height);

      // Check for semi-transparent pixels
      setHasSemiTransparent(checkForSemiTransparentPixels(imageData));

      const palette = getPalette();

      // Calculate target width based on aspect ratio
      const aspectRatio = img.width / img.height;
      const targetWidth = Math.round(targetHeight * aspectRatio);

      workerRef.current?.postMessage({
        imageData,
        settings: {
          targetWidth,
          targetHeight,
          ditherMethod,
          ditherStrength,
          palette,
          resamplingMethod,
          useKmeans,
          kmeansColors,
          brightness,
          contrast,
          saturation,
          preprocessingMethod,
          preprocessingStrength,
          filterTrivialColors,
          trivialThreshold,
          trivialThresholdMode,
          colorMatchAlgorithm,
          preserveDetailThreshold,
          pixeloeThickness,
          pixeloePatchSize,
          edgeDetectBlur,
          edgeDetectAlgorithm,
          colorStats: [],
          samplingMask: samplingMaskEnabled && samplingMask ? Array.from(samplingMask) : null,
          samplingMaskWidth: samplingMaskDims?.w || 0,
          samplingMaskHeight: samplingMaskDims?.h || 0,
        }
      });
    };
    img.src = layer.imageData;

  }, [layer.imageData, targetHeight, ditherMethod, ditherStrength, getPalette, resamplingMethod, useKmeans, kmeansColors, brightness, contrast, saturation, preprocessingMethod, preprocessingStrength, filterTrivialColors, trivialThreshold, trivialThresholdMode, colorMatchAlgorithm, preserveDetailThreshold, pixeloeThickness, pixeloePatchSize, edgeDetectBlur, edgeDetectAlgorithm, createWorker, samplingMaskEnabled, samplingMask, samplingMaskDims]);

  // Debounced Effect
  useEffect(() => {
    if (!isOpen || !autoUpdate) return;

    const timer = setTimeout(() => {
      processImage();
      debounceTimeRef.current = 750; // Reset to default after execution
    }, debounceTimeRef.current);

    return () => clearTimeout(timer);
  }, [
    isOpen,
    autoUpdate,
    targetHeight,
    ditherMethod,
    ditherStrength,
    paletteMode,
    customPaletteInput,
    resamplingMethod,
    useKmeans,
    kmeansColors,
    brightness,
    contrast,
    saturation,
    preprocessingMethod,
    preprocessingStrength,
    filterTrivialColors,
    trivialThreshold,
    trivialThresholdMode,
    colorMatchAlgorithm,
    preserveDetailThreshold,
    pixeloeThickness,
    pixeloePatchSize,
    edgeDetectBlur,
    edgeDetectAlgorithm,
    processImage
  ]);

  const handleApply = () => {
    if (previewImage && resultDimensions) {
      updateLayer(layer.id, {
        imageData: previewImage,
        width: resultDimensions.width,
        height: resultDimensions.height
      });
      // Auto-crop canvas when there's only one layer
      if (layers.length === 1) {
        setTimeout(() => { cropCanvasToLayers(); window.fitCanvasToScreen?.(); }, 50);
      }
      onClose();
    }
  };

  const calculateFitZoom = useCallback((width: number, height: number) => {
    if (!previewContainerRef.current) return 1;

    const containerWidth = previewContainerRef.current.clientWidth;
    const containerHeight = previewContainerRef.current.clientHeight;

    // Add some padding (e.g., 40px total)
    const availableWidth = containerWidth - 40;
    const availableHeight = containerHeight - 40;

    if (availableWidth <= 0 || availableHeight <= 0) return 1;

    const scaleX = availableWidth / width;
    const scaleY = availableHeight / height;

    // Use the smaller scale to ensure it fits entirely
    const newZoom = Math.min(scaleX, scaleY);

    return Math.max(0.1, newZoom);
  }, []);

  const handleZoomIn = () => setZoom(prev => Math.min(prev + 0.5, 20));
  const handleZoomOut = () => setZoom(prev => Math.max(prev - 0.5, 0.5));
  const handleZoomReset = () => setZoom(1);
  const handleFitToScreen = useCallback(() => {
    if (!imageDimensions) return;
    setZoom(calculateFitZoom(imageDimensions.width, imageDimensions.height));
  }, [imageDimensions, calculateFitZoom]);

  // Auto-fit on first load or when pinned
  useEffect(() => {
    if (imageDimensions && previewContainerRef.current) {
      if (!hasInitialFit) {
        // Small delay to ensure layout is stable
        setTimeout(() => {
          handleFitToScreen();
          setHasInitialFit(true);
        }, 50);
      }
    }
  }, [imageDimensions, hasInitialFit, handleFitToScreen]);

  const handleHeightReset = () => setTargetHeight(originalHeight);

  const checkForSemiTransparentPixels = (imageData: ImageData): boolean => {
    const data = imageData.data;
    for (let i = 3; i < data.length; i += 4) {
      const alpha = data[i];
      if (alpha > 0 && alpha < 255) {
        return true;
      }
    }
    return false;
  };

  const handleImageLoad = (e: React.SyntheticEvent<HTMLImageElement>) => {
    const img = e.currentTarget;
    setImageDimensions({
      width: img.naturalWidth,
      height: img.naturalHeight,
    });
  };

  // Compute effective palette (after trivial filtering) for suggest colors
  const getEffectivePalette = useCallback(() => {
    const palette = getPalette();
    if (!filterTrivialColors || colorStats.size === 0) return palette;

    const totalPixels = Array.from(colorStats.values()).reduce((s, v) => s + v.count, 0);
    return palette.filter(color => {
      const stats = colorStats.get(color);
      if (!stats) return true;
      if (trivialThresholdMode === 'pixels') return stats.count >= trivialThreshold;
      const percent = totalPixels > 0 ? (stats.count / totalPixels) * 100 : 0;
      return percent >= trivialThreshold;
    });
  }, [getPalette, filterTrivialColors, colorStats, trivialThreshold, trivialThresholdMode]);

  const handleSuggestColors = useCallback(() => {
    if (!workerRef.current || !layer.imageData) return;

    const palette = getEffectivePalette();
    if (palette.length === 0) {
      alert('Please select a palette first to find missing colors.');
      return;
    }

    setIsSuggesting(true);

    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      ctx.drawImage(img, 0, 0);
      const imageData = ctx.getImageData(0, 0, img.width, img.height);

      workerRef.current?.postMessage({
        type: 'suggest',
        imageData,
        settings: {
          palette,
          numSuggestions: suggestCount,
          preferDistinct: preferDistinctColors,
          samplingMask: samplingMaskEnabled && samplingMask ? Array.from(samplingMask) : null,
          samplingMaskWidth: samplingMaskDims?.w || 0,
          samplingMaskHeight: samplingMaskDims?.h || 0,
        }
      });
    };
    img.src = layer.imageData;
  }, [layer.imageData, getEffectivePalette, suggestCount, preferDistinctColors, samplingMaskEnabled, samplingMask, samplingMaskDims]);

  const handleAddSuggestedToCustom = () => {
    const existingText = customPaletteInput.trim();
    const newColors = suggestedColors.join(', ');

    if (existingText === '') {
      setCustomPaletteInput(newColors);
    } else {
      setCustomPaletteInput(`${existingText}, ${newColors}`);
    }
  };

  // Remove a color from the palette (switches to custom mode for built-in palettes)
  const handleRemoveColor = useCallback((colorToRemove: string) => {
    const currentPalette = getPalette();
    const surviving = currentPalette.filter(c => c.toUpperCase() !== colorToRemove.toUpperCase());
    if (surviving.length === 0) { setContextMenu(null); return; }
    setCustomPaletteInput(surviving.join(', '));
    if (paletteMode !== 'custom') setPaletteMode('custom');
    setContextMenu(null);
  }, [getPalette, paletteMode]);

  // Replace a color in the palette with a new hex value
  const handleReplaceColor = useCallback((oldColor: string, newHex: string) => {
    const cleaned = newHex.trim().replace(/^#/, '');
    if (!/^[0-9A-Fa-f]{6}$/.test(cleaned)) return;
    const newColor = '#' + cleaned.toUpperCase();
    const currentPalette = getPalette();
    const updated = currentPalette.map(c => c.toUpperCase() === oldColor.toUpperCase() ? newColor : c);
    setCustomPaletteInput(updated.join(', '));
    if (paletteMode !== 'custom') setPaletteMode('custom');
    setContextMenu(null);
  }, [getPalette, paletteMode]);

  // Prune unused colors — remove colors with 0 pixels in the preview
  const handlePruneColors = useCallback(() => {
    if (colorStats.size === 0) return;
    const currentPalette = getPalette();

    const survivingColors = currentPalette.filter(color => {
      const stats = colorStats.get(color);
      return stats != null && stats.count > 0;
    });

    if (survivingColors.length === 0) return;

    setCustomPaletteInput(survivingColors.join(', '));
    if (paletteMode !== 'custom') setPaletteMode('custom');
  }, [colorStats, getPalette, paletteMode]);

  // Click handler for palette swatches — shows action menu
  const handleSwatchContextMenu = useCallback((e: React.MouseEvent, color: string) => {
    e.stopPropagation();
    setContextMenu({ x: e.clientX, y: e.clientY, color });
  }, []);

  // Dismiss context menu on click outside
  useEffect(() => {
    if (!contextMenu) return;
    const handler = () => setContextMenu(null);
    window.addEventListener('click', handler);
    window.addEventListener('contextmenu', handler);
    return () => {
      window.removeEventListener('click', handler);
      window.removeEventListener('contextmenu', handler);
    };
  }, [contextMenu]);

  // Pixel highlight overlay — draw when highlightColor changes
  useEffect(() => {
    const canvas = highlightCanvasRef.current;
    const imgData = previewImageDataRef.current;
    if (!canvas || !imgData) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = imgData.width;
    canvas.height = imgData.height;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (!highlightColor) return;

    // Parse hex color to RGB
    const hr = parseInt(highlightColor.slice(1, 3), 16);
    const hg = parseInt(highlightColor.slice(3, 5), 16);
    const hb = parseInt(highlightColor.slice(5, 7), 16);

    const overlay = ctx.createImageData(imgData.width, imgData.height);
    const src = imgData.data;
    const dst = overlay.data;

    for (let i = 0; i < src.length; i += 4) {
      if (src[i + 3] === 0) continue;
      if (src[i] === hr && src[i + 1] === hg && src[i + 2] === hb) {
        // Matching pixel — bright cyan highlight
        dst[i] = 0; dst[i + 1] = 255; dst[i + 2] = 255; dst[i + 3] = 160;
      } else {
        // Non-matching — dim overlay
        dst[i] = 0; dst[i + 1] = 0; dst[i + 2] = 0; dst[i + 3] = 120;
      }
    }
    ctx.putImageData(overlay, 0, 0);
  }, [highlightColor]);

  // Active color count
  const activeColorCount = useMemo(() => {
    const palette = getPalette();
    if (colorStats.size === 0) return { active: 0, total: palette.length };
    let active = 0;
    for (const color of palette) {
      const stats = colorStats.get(color);
      if (stats && stats.count > 0) active++;
    }
    return { active, total: palette.length };
  }, [getPalette, colorStats]);

  // Reset all settings to defaults
  const handleResetSettings = useCallback(() => {
    setTargetHeight(128);
    setResamplingMethod('bilinear');
    setDitherMethod('none');
    setDitherStrength(100);
    setPreprocessingMethod('none');
    setPreprocessingStrength(50);
    setPaletteMode('geopixels');
    setUseKmeans(false);
    setKmeansColors(16);
    setBrightness(0);
    setContrast(0);
    setSaturation(0);
    setColorMatchAlgorithm('oklab');
    setPreserveDetailThreshold(0);
    setFilterTrivialColors(false);
    setTrivialThreshold(0.1);
    setDisplayTrivialThreshold('0.1');
    setTrivialThresholdMode('percent');
    setPixeloeThickness(2);
    setPixeloePatchSize(16);
    setEdgeDetectBlur(0);
    setEdgeDetectAlgorithm('sobel');
    setAutoUpdate(true);
    setIsPaletteVisualizationOpen(true);
    setIsExtraFeaturesOpen(false);
    setSamplingMaskEnabled(false);
    setSamplingMask(null);
    setSamplingMaskDims(null);
    localStorage.removeItem('pixelator_settings');
  }, []);

  // ─── Preset management ─────────────────────────────────────────────
  const getCurrentSettings = useCallback((): Record<string, any> => ({
    targetHeight, resamplingMethod, ditherMethod, ditherStrength,
    preprocessingMethod, preprocessingStrength, paletteMode,
    useKmeans, kmeansColors, brightness, contrast, saturation,
    colorMatchAlgorithm, preserveDetailThreshold,
    filterTrivialColors, trivialThreshold, trivialThresholdMode,
    pixeloeThickness, pixeloePatchSize, edgeDetectBlur, edgeDetectAlgorithm,
    autoUpdate, customPaletteInput, selectedPreset, includeGeopixelsBase,
  }), [targetHeight, resamplingMethod, ditherMethod, ditherStrength,
    preprocessingMethod, preprocessingStrength, paletteMode,
    useKmeans, kmeansColors, brightness, contrast, saturation,
    colorMatchAlgorithm, preserveDetailThreshold,
    filterTrivialColors, trivialThreshold, trivialThresholdMode,
    pixeloeThickness, pixeloePatchSize, edgeDetectBlur, edgeDetectAlgorithm,
    autoUpdate, customPaletteInput, selectedPreset, includeGeopixelsBase]);

  const savePreset = useCallback((name: string) => {
    if (!name.trim()) return;
    const newPreset = { name: name.trim(), settings: getCurrentSettings() };
    const updated = [...presets, newPreset];
    setPresets(updated);
    localStorage.setItem('pixelator_presets', JSON.stringify(updated));
    setPresetName('');
  }, [getCurrentSettings, presets]);

  const loadPreset = useCallback((settings: Record<string, any>) => {
    if (settings.targetHeight != null) setTargetHeight(settings.targetHeight);
    if (settings.resamplingMethod) setResamplingMethod(settings.resamplingMethod);
    if (settings.ditherMethod) setDitherMethod(settings.ditherMethod);
    if (settings.ditherStrength != null) setDitherStrength(settings.ditherStrength);
    if (settings.preprocessingMethod) setPreprocessingMethod(settings.preprocessingMethod);
    if (settings.preprocessingStrength != null) setPreprocessingStrength(settings.preprocessingStrength);
    if (settings.paletteMode) setPaletteMode(settings.paletteMode);
    if (settings.useKmeans != null) setUseKmeans(settings.useKmeans);
    if (settings.kmeansColors != null) setKmeansColors(settings.kmeansColors);
    if (settings.brightness != null) setBrightness(settings.brightness);
    if (settings.contrast != null) setContrast(settings.contrast);
    if (settings.saturation != null) setSaturation(settings.saturation);
    if (settings.colorMatchAlgorithm) setColorMatchAlgorithm(settings.colorMatchAlgorithm);
    if (settings.preserveDetailThreshold != null) setPreserveDetailThreshold(settings.preserveDetailThreshold);
    if (settings.filterTrivialColors != null) setFilterTrivialColors(settings.filterTrivialColors);
    if (settings.trivialThreshold != null) { setTrivialThreshold(settings.trivialThreshold); setDisplayTrivialThreshold(String(settings.trivialThreshold)); }
    if (settings.trivialThresholdMode) setTrivialThresholdMode(settings.trivialThresholdMode);
    if (settings.pixeloeThickness != null) setPixeloeThickness(settings.pixeloeThickness);
    if (settings.pixeloePatchSize != null) setPixeloePatchSize(settings.pixeloePatchSize);
    if (settings.edgeDetectBlur != null) setEdgeDetectBlur(settings.edgeDetectBlur);
    if (settings.edgeDetectAlgorithm) setEdgeDetectAlgorithm(settings.edgeDetectAlgorithm);
    if (settings.autoUpdate != null) setAutoUpdate(settings.autoUpdate);
    if (settings.customPaletteInput != null) setCustomPaletteInput(settings.customPaletteInput);
    if (settings.selectedPreset != null) setSelectedPreset(settings.selectedPreset);
    if (settings.includeGeopixelsBase != null) setIncludeGeopixelsBase(settings.includeGeopixelsBase);
    // Migrate old geopixels+custom profiles
    if (settings.paletteMode === 'geopixels+custom') { setPaletteMode('custom'); setIncludeGeopixelsBase(true); }
    debounceTimeRef.current = 100;
    setIsPresetsModalOpen(false);
  }, []);

  const deletePreset = useCallback((index: number) => {
    const updated = presets.filter((_, i) => i !== index);
    setPresets(updated);
    localStorage.setItem('pixelator_presets', JSON.stringify(updated));
  }, [presets]);

  const movePreset = useCallback((index: number, direction: 'up' | 'down') => {
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex < 0 || newIndex >= presets.length) return;
    const updated = [...presets];
    [updated[index], updated[newIndex]] = [updated[newIndex], updated[index]];
    setPresets(updated);
    localStorage.setItem('pixelator_presets', JSON.stringify(updated));
  }, [presets]);

  const sortedPalette = useMemo(() => {
    let currentPalette = getPalette();

    // Use generated palette if available and we're in 'none' mode with K-Means
    if (paletteMode === 'none' && useKmeans && generatedPalette.length > 0) {
      currentPalette = generatedPalette;
    }

    if (colorStats.size === 0) return currentPalette;

    return [...currentPalette].sort((a, b) => {
      const countA = colorStats.get(a)?.count || 0;
      const countB = colorStats.get(b)?.count || 0;

      // Sort by count descending
      if (countA !== countB) {
        return countB - countA;
      }

      // If counts are equal, keep original order (stable sort)
      return 0;
    });
  }, [getPalette, colorStats, generatedPalette, paletteMode, useKmeans]);

  const handleCopyPalette = () => {
    if (sortedPalette.length > 0) {
      navigator.clipboard.writeText(sortedPalette.join(', '));
    }
  };

  // Before/After comparison slider handlers
  const handleCompareMouseDown = useCallback((e: React.MouseEvent) => {
    isDraggingCompare.current = true;
    e.preventDefault();
  }, []);

  const handleCompareMove = useCallback((clientX: number) => {
    if (!compareContainerRef.current) return;
    const rect = compareContainerRef.current.getBoundingClientRect();
    const x = clientX - rect.left;
    const percent = Math.max(0, Math.min(100, (x / rect.width) * 100));
    setComparePosition(percent);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDraggingCompare.current) return;
      handleCompareMove(e.clientX);
    };
    const handleMouseUp = () => {
      isDraggingCompare.current = false;
    };
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [handleCompareMove]);

  // Eyedropper: add picked colors to custom palette text field
  const handleEyedropperColors = (colors: string[]) => {
    if (colors.length === 0) return;
    const newColors = colors.join(', ');
    const existing = customPaletteInput.trim();
    if (existing === '') {
      setCustomPaletteInput(newColors);
    } else {
      setCustomPaletteInput(`${existing}, ${newColors}`);
    }
    // Auto-switch to custom if not already
    if (paletteMode !== 'custom' && paletteMode !== 'geopixels+custom') {
      debounceTimeRef.current = 100;
      setPaletteMode('custom');
    }
  };

  // GeoPixels palette: add fetched colors to custom palette text field
  const handleGeoPixelsColors = (colors: string[]) => {
    if (colors.length === 0) return;
    const newColors = colors.join(', ');
    const existing = customPaletteInput.trim();
    if (existing === '') {
      setCustomPaletteInput(newColors);
    } else {
      setCustomPaletteInput(`${existing}, ${newColors}`);
    }
    // Auto-switch to custom if not already
    if (paletteMode !== 'custom' && paletteMode !== 'geopixels+custom') {
      debounceTimeRef.current = 100;
      setPaletteMode('custom');
    }
  };

  // K-Means: Send generated palette colors to Custom text field
  const handleSendKmeansToCustom = () => {
    if (generatedPalette.length === 0) return;
    const newColors = generatedPalette.join(', ');
    const existing = customPaletteInput.trim();
    if (existing === '') {
      setCustomPaletteInput(newColors);
    } else {
      setCustomPaletteInput(`${existing}, ${newColors}`);
    }
    // Switch to Custom mode
    debounceTimeRef.current = 100;
    setPaletteMode('custom');
  };

  return (
    <DraggableModal isOpen={isOpen} title="Pixelator" onClose={onClose} noPadding={true} modalId="modal-pixelator" children={() => (
      <div className={`${isPortrait ? 'flex flex-col-reverse' : 'flex'} text-gray-200 h-full w-full overflow-hidden`}>
        {/* Controls */}
        <div className={`${isPortrait ? 'border-t max-h-[45vh]' : 'w-72 border-r'} border-gray-700 flex-shrink-0 flex flex-col overflow-hidden`}>
          {/* Scrollable content area */}
          <div className="overflow-y-auto flex-1 p-4 space-y-6 text-gray-200">

            {/* Dimensions */}
            <div className="space-y-2">
              <label className="text-xs font-semibold text-gray-400 uppercase">Dimensions</label>
              <div className="space-y-2">
                <div className="flex gap-2 items-end">
                  <div className="flex-1">
                    <label className="text-xs text-gray-500">Height (px)</label>
                    <input
                      type="text"
                      inputMode="numeric"
                      value={displayHeight}
                      onChange={(e) => {
                        // Update display value
                        setDisplayHeight(e.target.value);
                        // Only update state if it's a valid number
                        if (e.target.value !== '' && e.target.value !== '-') {
                          const value = Number(e.target.value);
                          if (!isNaN(value) && value > 0) {
                            setTargetHeight(value);
                          }
                        }
                      }}
                      className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm"
                    />
                  </div>
                  <select
                    className="flex-1 bg-gray-800 border border-gray-600 rounded px-2 py-1 text-xs text-gray-400"
                    onChange={(e) => {
                      if (e.target.value) {
                        debounceTimeRef.current = 100; // Fast update for dropdown
                        setTargetHeight(Number(e.target.value));
                      }
                    }}
                    value={COMMON_HEIGHTS.includes(targetHeight) ? targetHeight : ""}
                  >
                    <option value="" disabled>common sizes</option>
                    {COMMON_HEIGHTS.map(h => (
                      <option key={h} value={h}>{h}px</option>
                    ))}
                  </select>
                  <button
                    onClick={handleHeightReset}
                    className="text-xs px-2 py-1 text-gray-400 hover:text-white bg-gray-700 hover:bg-gray-600 rounded transition-colors whitespace-nowrap flex-shrink-0"
                    title="Reset height to default"
                  >
                    Reset
                  </button>
                </div>

                {resultDimensions && (
                  <div className="text-xs text-gray-400 bg-gray-800 px-2 py-1 rounded whitespace-nowrap">
                    {resultDimensions.width} × {resultDimensions.height} <span className="text-gray-600 mx-1">|</span> {Array.from(colorStats.values()).reduce((sum, s) => sum + s.count, 0).toLocaleString()} px
                  </div>
                )}
              </div>
              <div>
                <label className="text-xs text-gray-500">Resampling</label>
                <select
                  value={resamplingMethod}
                  onChange={(e) => setResamplingMethod(e.target.value as any)}
                  className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm"
                >
                  <option value="nearest">Nearest Neighbor (Sharp)</option>
                  <option value="bilinear">Bilinear (Smooth)</option>
                  <option value="lanczos">Lanczos (High Quality)</option>
                  <option value="pixeloe-nearest">⚠️ PixelOE Nearest (Experimental)</option>
                  <option value="pixeloe-contrast">⚠️ PixelOE Contrast (Experimental)</option>
                  <option value="pixeloe-k-centroid">⚠️ PixelOE K-Centroid (Experimental)</option>
                </select>
                {(resamplingMethod === 'pixeloe-nearest' || resamplingMethod === 'pixeloe-contrast' || resamplingMethod === 'pixeloe-k-centroid') && (
                  <div className="mt-2 space-y-2 bg-yellow-900/20 border border-yellow-700/50 rounded p-2">
                    <div className="flex items-center gap-1 text-xs text-yellow-400 font-semibold">
                      <span>⚠️</span>
                      <span>PixelOE — Outline-Aware Pixelization</span>
                    </div>
                    <p className="text-xs text-yellow-300/70">
                      {resamplingMethod === 'pixeloe-nearest'
                        ? 'Outline expansion then nearest-neighbor downscale. Clean and fast — recommended starting point.'
                        : resamplingMethod === 'pixeloe-contrast'
                        ? 'Contrast-aware downscaling in LAB space. Preserves dark/bright details by adaptively selecting pixels per patch.'
                        : 'K-means clustering per tile to find the dominant color. Produces clean, flat pixel art.'}
                    </p>
                    <div>
                      <div className="flex justify-between text-xs text-gray-400">
                        <span>Outline Thickness</span>
                        <span>{pixeloeThickness}</span>
                      </div>
                      <input
                        type="range"
                        min="1"
                        max="4"
                        value={pixeloeThickness}
                        onChange={(e) => setPixeloeThickness(Number(e.target.value))}
                        className="w-full"
                      />
                    </div>
                    <div>
                      <div className="flex justify-between text-xs text-gray-400">
                        <span>Patch Size</span>
                        <span>{pixeloePatchSize}px</span>
                      </div>
                      <input
                        type="range"
                        min="4"
                        max="32"
                        step="4"
                        value={pixeloePatchSize}
                        onChange={(e) => setPixeloePatchSize(Number(e.target.value))}
                        className="w-full"
                      />
                    </div>
                  </div>
                )}
              </div>
              <div>
                <label className="text-xs text-gray-500">Color Matching</label>
                <select
                  value={colorMatchAlgorithm}
                  onChange={(e) => { debounceTimeRef.current = 100; setColorMatchAlgorithm(e.target.value); }}
                  className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm"
                  title={COLOR_MATCH_ALGORITHMS.find(a => a.value === colorMatchAlgorithm)?.desc}
                >
                  {COLOR_MATCH_ALGORITHMS.map(a => (
                    <option key={a.value} value={a.value}>{a.label}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Semi-Transparent Warning */}
            {hasSemiTransparent && (
              <div className="bg-yellow-900/30 border border-yellow-700 rounded p-3 flex gap-3">
                <div className="text-yellow-500 text-xl flex-shrink-0">⚠️</div>
                <div className="text-xs text-yellow-300">
                  <p className="font-semibold mb-1">Semi-transparent pixels detected</p>
                  <p>Apply a transparency mask first for better results</p>
                </div>
              </div>
            )}

            {/* Palette */}
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <label className="text-xs font-semibold text-gray-400 uppercase">Palette</label>
                {(paletteMode === 'custom' && includeGeopixelsBase) && (
                  <div className="group relative">
                    <span className="cursor-help text-xs text-blue-400">Fun Fact?</span>
                    <div className="absolute bottom-full right-0 mb-2 w-64 p-2 bg-gray-900 border border-gray-600 rounded shadow-xl text-xs text-gray-300 hidden group-hover:block z-50">
                      If you play on Geopixels, you can export your palette by typing <code className="text-yellow-400">userData.colors</code> in the browser console. Paste the result here!
                    </div>
                  </div>
                )}
              </div>

              <div className="flex flex-col space-y-1">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="radio"
                    name="palette"
                    checked={paletteMode === 'preset'}
                    onChange={() => { debounceTimeRef.current = 100; setPaletteMode('preset'); }}
                  />
                  <span className="text-sm">Presets</span>
                </label>
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="radio"
                    name="palette"
                    checked={paletteMode === 'custom'}
                    onChange={() => { debounceTimeRef.current = 100; setPaletteMode('custom'); }}
                  />
                  <span className="text-sm">Custom</span>
                </label>
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="radio"
                    name="palette"
                    checked={paletteMode === 'none'}
                    onChange={() => { debounceTimeRef.current = 100; setPaletteMode('none'); }}
                  />
                  <span className="text-sm">No Recoloring (Resize Only)</span>
                </label>
              </div>

              {paletteMode === 'preset' && (
                <div className="space-y-1">
                  <select
                    value={selectedPreset}
                    onChange={(e) => { setSelectedPreset(e.target.value); debounceTimeRef.current = 100; }}
                    className="w-full px-2 py-1.5 bg-gray-800 border border-gray-600 rounded text-xs text-green-300 cursor-pointer"
                  >
                    {PRESET_PALETTES.map(p => (
                      <option key={p.label} value={p.label}>{p.label} ({p.palette.length} colors)</option>
                    ))}
                  </select>
                </div>
              )}

              {paletteMode === 'custom' && (
                <div className="space-y-2">
                  <textarea
                    value={customPaletteInput}
                    onChange={(e) => setCustomPaletteInput(e.target.value)}
                    placeholder="#FFFFFF, #000000 or 16777215, 0"
                    className="w-full h-24 bg-gray-800 border border-gray-600 rounded p-2 text-xs font-mono"
                  />
                  <label className="flex items-center space-x-2 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={includeGeopixelsBase}
                      onChange={(e) => { setIncludeGeopixelsBase(e.target.checked); debounceTimeRef.current = 100; }}
                      className="rounded border-gray-600 bg-gray-700 text-blue-600 focus:ring-blue-500 focus:ring-offset-gray-800"
                    />
                    <span className="text-xs text-gray-400">Include Geopixels Base Colors</span>
                  </label>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => setIsEyedropperOpen(true)}
                      className="flex-1 px-3 py-1.5 bg-gray-700 hover:bg-gray-600 text-red-300 text-xs font-medium rounded transition-colors"
                    >
                      Eyedropper
                    </button>
                    <button
                      onClick={() => setIsGeoPixelsPaletteOpen(true)}
                      className="flex-1 px-3 py-1.5 bg-gray-700 hover:bg-gray-600 text-blue-300 text-xs font-medium rounded transition-colors"
                      title="Fetch your owned colors from GeoPixels"
                    >
                      My Colors
                    </button>
                    <div className="group relative">
                      <span className="cursor-help text-xs text-blue-400">?</span>
                      <div className="absolute bottom-full right-0 mb-2 w-52 p-2 bg-gray-900 border border-gray-600 rounded shadow-xl text-xs text-gray-300 hidden group-hover:block z-50">
                        Select colors to use from template image
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => setIsGradientPickerOpen(true)}
                      className="flex-1 px-3 py-1.5 bg-gray-700 hover:bg-gray-600 text-purple-300 text-xs font-medium rounded transition-colors"
                      title="Drag across the image to capture gradient colors"
                    >
                      Gradients
                    </button>
                    <button
                      onClick={() => setIsGroupNoiseOpen(true)}
                      className="flex-1 px-3 py-1.5 bg-gray-700 hover:bg-gray-600 text-yellow-300 text-xs font-medium rounded transition-colors"
                      title="Detect and merge colors that are too similar (triggers Group Noise on GeoPixels)"
                    >
                      Group Noise
                    </button>
                    <div className="invisible">
                      <span className="cursor-help text-xs text-blue-400">?</span>
                    </div>
                  </div>
                </div>
              )}

              {/* Palette Visualization */}
              <div className="border-t border-gray-700 pt-2">
                <div className="flex items-center justify-between mb-2">
                  <button
                    onClick={() => setIsPaletteVisualizationOpen(!isPaletteVisualizationOpen)}
                    className="flex items-center text-xs text-gray-400 hover:text-gray-300"
                  >
                    <span>Palette Preview</span>
                    <span className="ml-1">{isPaletteVisualizationOpen ? '▼' : '▶'}</span>
                  </button>
                  <button
                    onClick={handleCopyPalette}
                    className="text-gray-400 hover:text-white p-1 rounded hover:bg-gray-700"
                    title="Copy palette to clipboard"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m2 4h3a2 2 0 012 2v3m-3-3V5a2 2 0 012-2h3.071a2 2 0 011.414.586l1.414 1.414A2 2 0 0118 6.414V9m-3-3h3" />
                    </svg>
                  </button>
                </div>

                {isPaletteVisualizationOpen && (
                  <div className="space-y-2">
                    <div className="flex flex-wrap gap-0 bg-gray-900 p-1 rounded border border-gray-700">
                      {sortedPalette.length > 0 ? (
                        sortedPalette.map((color, idx) => (
                          <div
                            key={idx}
                            className="w-4 h-4 cursor-crosshair hover:z-10 hover:scale-125 transition-transform duration-75 border border-transparent hover:border-white"
                            style={{ backgroundColor: color }}
                            onMouseEnter={(e) => {
                              setHoveredColor(color);
                              setHighlightColor(color);
                              setHoverPos({ x: e.clientX, y: e.clientY });
                            }}
                            onMouseLeave={() => {
                              setHoveredColor(null);
                              setHighlightColor(null);
                              setHoverPos(null);
                            }}
                            onMouseMove={(e) => {
                              setHoverPos({ x: e.clientX, y: e.clientY });
                            }}
                            onClick={(e) => handleSwatchContextMenu(e, color)}
                          />
                        ))
                      ) : (
                        <div className="text-xs text-gray-500 p-2">No palette selected</div>
                      )}
                    </div>

                    {/* Active color count */}
                    {activeColorCount.total > 0 && colorStats.size > 0 && (
                      <div className="text-xs text-gray-500">
                        {activeColorCount.active} / {activeColorCount.total} colors used
                      </div>
                    )}

                    {/* Context Menu */}
                    {contextMenu && (
                      <div
                        style={{ position: 'fixed', left: contextMenu.x, top: contextMenu.y, zIndex: 9999 }}
                        className="bg-gray-800 border border-gray-600 rounded shadow-xl py-1 min-w-[160px]"
                        onClick={(e) => e.stopPropagation()}
                      >
                        <div className="flex items-center gap-2 px-3 py-1.5 border-b border-gray-700">
                          <div className="w-3 h-3 border border-gray-500 rounded-sm" style={{ backgroundColor: contextMenu.color }} />
                          <span className="text-xs font-mono text-gray-300">{contextMenu.color}</span>
                        </div>
                        {contextMenu.editing ? (
                          <div className="px-3 py-2 space-y-2">
                            <div className="flex items-center gap-1.5">
                              <input
                                type="color"
                                value={(contextMenu.editValue && /^#[0-9A-Fa-f]{6}$/i.test(contextMenu.editValue)) ? contextMenu.editValue : contextMenu.color}
                                onChange={(e) => setContextMenu(prev => prev ? { ...prev, editValue: e.target.value.toUpperCase() } : null)}
                                className="w-6 h-6 p-0 border border-gray-600 rounded cursor-pointer bg-transparent"
                              />
                              <input
                                type="text"
                                autoFocus
                                value={contextMenu.editValue ?? contextMenu.color}
                                onChange={(e) => setContextMenu(prev => prev ? { ...prev, editValue: e.target.value.toUpperCase() } : null)}
                                onKeyDown={(e) => { if (e.key === 'Enter') handleReplaceColor(contextMenu.color, contextMenu.editValue ?? contextMenu.color); if (e.key === 'Escape') setContextMenu(null); }}
                                placeholder="#FF00FF"
                                className="flex-1 min-w-0 bg-gray-900 border border-gray-600 rounded px-1.5 py-0.5 text-xs font-mono text-gray-200 focus:border-blue-500 focus:outline-none"
                              />
                            </div>
                            <div className="flex gap-1.5">
                              <button
                                className="flex-1 px-2 py-1 bg-blue-600 hover:bg-blue-500 text-white text-xs rounded transition-colors"
                                onClick={() => handleReplaceColor(contextMenu.color, contextMenu.editValue ?? contextMenu.color)}
                              >
                                Apply
                              </button>
                              <button
                                className="flex-1 px-2 py-1 bg-gray-700 hover:bg-gray-600 text-gray-300 text-xs rounded transition-colors"
                                onClick={() => setContextMenu(null)}
                              >
                                Cancel
                              </button>
                            </div>
                          </div>
                        ) : (
                          <>
                            <button
                              className="w-full text-left px-3 py-1.5 text-xs text-gray-300 hover:bg-gray-700 hover:text-white"
                              onClick={() => { navigator.clipboard.writeText(contextMenu.color); setContextMenu(null); }}
                            >
                              Copy Hex
                            </button>
                            <button
                              className="w-full text-left px-3 py-1.5 text-xs text-gray-300 hover:bg-gray-700 hover:text-white"
                              onClick={() => setContextMenu(prev => prev ? { ...prev, editing: true, editValue: prev.color } : null)}
                            >
                              Edit Color
                            </button>
                            <button
                              className="w-full text-left px-3 py-1.5 text-xs text-red-400 hover:bg-gray-700 hover:text-red-300"
                              onClick={() => handleRemoveColor(contextMenu.color)}
                            >
                              Remove Color
                            </button>
                          </>
                        )}
                      </div>
                    )}

                    {/* Hover Tooltip */}
                    {hoveredColor && hoverPos && (
                      <div
                        style={{
                          position: 'fixed',
                          left: hoverPos.x + 15,
                          top: hoverPos.y + 15,
                          zIndex: 9999,
                          pointerEvents: 'none'
                        }}
                        className="bg-gray-900 border border-gray-600 rounded p-2 shadow-xl text-xs min-w-[120px]"
                      >
                        <div className="flex items-center gap-2 mb-1 pb-1 border-b border-gray-700">
                          <div
                            className="w-3 h-3 border border-gray-500"
                            style={{ backgroundColor: hoveredColor }}
                          />
                          <span className="font-mono font-bold text-white">{hoveredColor}</span>
                        </div>
                        {colorStats.has(hoveredColor) ? (
                          <div className="text-gray-300 space-y-0.5">
                            <div className="flex justify-between gap-4">
                              <span>Count:</span>
                              <span className="text-white font-mono">{colorStats.get(hoveredColor)?.count.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between gap-4">
                              <span>Usage:</span>
                              <span className="text-white font-mono">{colorStats.get(hoveredColor)?.percent.toFixed(2)}%</span>
                            </div>
                          </div>
                        ) : (
                          <div className="text-gray-500 italic">Not used in preview</div>
                        )}
                      </div>
                    )}

                    {/* Filter trivial colors — available for all palette modes except 'none' */}
                    {paletteMode !== 'none' && (
                      <div className="space-y-2 border-t border-gray-700 pt-2 pb-0">
                        <div className="flex items-center gap-2">
                          <label className="flex items-center space-x-2 cursor-pointer flex-shrink-0">
                            <input 
                              type="checkbox" 
                              checked={filterTrivialColors}
                              onChange={(e) => setFilterTrivialColors(e.target.checked)}
                              className="rounded border-gray-600 bg-gray-700 text-blue-600 focus:ring-blue-500 focus:ring-offset-gray-800"
                              title={trivialThresholdMode === 'percent'
                                ? `Ignore colors below ${trivialThreshold}% usage during processing`
                                : `Ignore colors with fewer than ${trivialThreshold} pixels during processing`}
                            />
                            <span className="text-xs text-gray-400">Filter trivial colors</span>
                          </label>
                        </div>
                        <div className="flex items-center gap-1">
                          <span className="text-xs text-gray-500">&lt;</span>
                          <div className="flex items-center">
                            <input
                              type="text"
                              value={displayTrivialThreshold}
                              onChange={(e) => {
                                setDisplayTrivialThreshold(e.target.value);
                                const val = parseFloat(e.target.value);
                                if (trivialThresholdMode === 'percent') {
                                  if (!isNaN(val) && val > 0 && val <= 100) {
                                    setTrivialThreshold(val);
                                  }
                                } else {
                                  if (!isNaN(val) && val > 0 && Number.isFinite(val)) {
                                    setTrivialThreshold(val);
                                  }
                                }
                              }}
                              onBlur={() => {
                                const val = parseFloat(displayTrivialThreshold);
                                if (trivialThresholdMode === 'percent') {
                                  if (isNaN(val) || val <= 0) {
                                    setTrivialThreshold(0.1);
                                    setDisplayTrivialThreshold('0.1');
                                  } else {
                                    setDisplayTrivialThreshold(String(val));
                                  }
                                } else {
                                  if (isNaN(val) || val <= 0) {
                                    setTrivialThreshold(1);
                                    setDisplayTrivialThreshold('1');
                                  } else {
                                    const rounded = Math.round(val);
                                    setTrivialThreshold(rounded);
                                    setDisplayTrivialThreshold(String(rounded));
                                  }
                                }
                              }}
                              className="w-14 bg-gray-800 border border-gray-600 rounded-l px-1.5 py-0.5 text-xs text-center font-mono"
                              title={trivialThresholdMode === 'percent'
                                ? 'Threshold percentage for trivial color filtering'
                                : 'Minimum pixel count for a color to be kept'}
                            />
                            <div className="flex flex-col">
                              <button
                                onClick={() => {
                                  const step = trivialThresholdMode === 'percent' ? 0.01 : 1;
                                  const max = trivialThresholdMode === 'percent' ? 100 : 999999;
                                  const next = Math.min(max, trivialThresholdMode === 'percent'
                                    ? Math.round((trivialThreshold + step) * 100) / 100
                                    : trivialThreshold + step);
                                  setTrivialThreshold(next);
                                  setDisplayTrivialThreshold(String(next));
                                }}
                                className="bg-gray-700 hover:bg-gray-600 border border-gray-600 border-l-0 rounded-tr px-1 leading-none text-[9px] text-gray-300 h-[11px] flex items-center"
                                title={trivialThresholdMode === 'percent' ? 'Increase by 0.01%' : 'Increase by 1 pixel'}
                              >▲</button>
                              <button
                                onClick={() => {
                                  const step = trivialThresholdMode === 'percent' ? 0.01 : 1;
                                  const min = trivialThresholdMode === 'percent' ? 0.01 : 1;
                                  const next = Math.max(min, trivialThresholdMode === 'percent'
                                    ? Math.round((trivialThreshold - step) * 100) / 100
                                    : trivialThreshold - step);
                                  setTrivialThreshold(next);
                                  setDisplayTrivialThreshold(String(next));
                                }}
                                className="bg-gray-700 hover:bg-gray-600 border border-gray-600 border-l-0 border-t-0 rounded-br px-1 leading-none text-[9px] text-gray-300 h-[11px] flex items-center"
                                title={trivialThresholdMode === 'percent' ? 'Decrease by 0.01%' : 'Decrease by 1 pixel'}
                              >▼</button>
                            </div>
                          </div>
                          <select
                            value={trivialThresholdMode}
                            onChange={(e) => {
                              const newMode = e.target.value as 'percent' | 'pixels';
                              setTrivialThresholdMode(newMode);
                              if (newMode === 'percent') {
                                setTrivialThreshold(0.1);
                                setDisplayTrivialThreshold('0.1');
                              } else {
                                setTrivialThreshold(1);
                                setDisplayTrivialThreshold('1');
                              }
                            }}
                            className="bg-gray-800 border border-gray-600 rounded px-1 py-0.5 text-xs text-gray-400"
                            title="Choose threshold unit"
                          >
                            <option value="percent">%</option>
                            <option value="pixels">px</option>
                          </select>
                        </div>
                        {colorStats.size > 0 && (
                          <button
                            onClick={handlePruneColors}
                            className="w-full px-2 py-1 bg-red-900/50 hover:bg-red-800/60 text-red-300 text-xs rounded border border-red-700/50 transition-colors"
                            title="Remove all palette colors that have zero pixels in the current preview"
                          >
                            Prune Unused Colors
                          </button>
                        )}
                      </div>
                    )}

                    {/* Suggest Colors moved below Palette Preview */}
                  </div>
                )}
              </div>

              {/* Suggest Colors — always visible for custom palette mode */}
              {paletteMode === 'custom' && (
                <div className="space-y-2 border-t border-gray-700 pt-2">
                  <div className="flex items-center justify-between gap-2">
                    <label className="text-xs font-semibold text-gray-400 uppercase whitespace-nowrap">Suggest Colors</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="number"
                        min="1"
                        max="32"
                        value={suggestCount}
                        onChange={(e) => setSuggestCount(Math.max(1, Math.min(32, Number(e.target.value))))}
                        className="w-12 bg-gray-800 border border-gray-600 rounded px-1 py-0.5 text-xs text-center"
                        title="Number of colors to suggest"
                      />
                      <button
                        onClick={handleSuggestColors}
                        disabled={isSuggesting}
                        className="px-3 py-1 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-600 disabled:cursor-not-allowed text-white text-xs rounded transition-colors"
                      >
                        {isSuggesting ? '...' : 'Go'}
                      </button>
                    </div>
                  </div>
                  <label className="flex items-center space-x-2 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={preferDistinctColors}
                      onChange={(e) => setPreferDistinctColors(e.target.checked)}
                      className="rounded border-gray-600 bg-gray-700 text-blue-600 focus:ring-blue-500 focus:ring-offset-gray-800"
                      title="Prioritize colors that are distinct from each other"
                    />
                    <span className="text-xs text-gray-400">Prefer distinct color suggestions</span>
                  </label>

                  {suggestedColors.length > 0 && (
                    <div className="space-y-2">
                      <div className="flex flex-wrap gap-1 bg-gray-900 p-2 rounded border border-gray-700">
                        {suggestedColors.map((color, idx) => (
                          <div
                            key={idx}
                            className="w-8 h-8 rounded border border-gray-500 cursor-pointer hover:border-white"
                            style={{ backgroundColor: color }}
                            title={`${color} - Click to copy`}
                            onClick={() => { navigator.clipboard.writeText(color); }}
                          />
                        ))}
                      </div>
                      <button
                        onClick={handleAddSuggestedToCustom}
                        className="w-full px-2 py-1 bg-gray-700 hover:bg-gray-600 text-white text-xs rounded transition-colors"
                      >
                        Add to Custom Palette
                      </button>
                    </div>
                  )}

                  <p className="text-xs text-gray-500">Analyzes the image to find dominant colors missing from your palette.</p>
                </div>
              )}
            </div>

            {/* Dithering */}
            <div className="space-y-2">
              <label className="text-xs font-semibold text-gray-400 uppercase">Dithering</label>
              <select
                value={ditherMethod}
                onChange={(e) => { debounceTimeRef.current = 100; setDitherMethod(e.target.value); }}
                className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm"
              >
                {DITHER_ALGORITHMS.map(algo => (
                  <option key={algo.value} value={algo.value}>{algo.label}</option>
                ))}
              </select>

              {ditherMethod !== 'none' && (
                <div>
                  <div className="flex justify-between text-xs text-gray-500">
                    <span>Strength</span>
                    <span>{ditherStrength}%</span>
                  </div>
                  <input
                    type="range"
                    min="0"
                    max="100"
                    value={ditherStrength}
                    onChange={(e) => setDitherStrength(Number(e.target.value))}
                    className="w-full"
                  />
                </div>
              )}
            </div>

            {/* K-Means Clustering */}
            <div className="space-y-2">
              <div className="group relative inline-block w-full">
                <label className={`flex items-center space-x-2 ${paletteMode !== 'none' ? 'cursor-not-allowed opacity-50' : 'cursor-pointer'}`}>
                  <input
                    type="checkbox"
                    checked={useKmeans}
                    onChange={(e) => setUseKmeans(e.target.checked)}
                    disabled={paletteMode !== 'none'}
                  />
                  <span className="text-xs font-semibold text-gray-400 uppercase">K-Means Color Reduction</span>
                </label>
                {paletteMode !== 'none' && (
                  <div className="absolute bottom-full left-0 mb-2 w-64 p-2 bg-gray-900 border border-gray-600 rounded shadow-xl text-xs text-gray-300 hidden group-hover:block z-50">
                    K-Means is only available when "No Recoloring" is selected. It's used to reduce the color space when you're not providing a specific palette.
                  </div>
                )}
              </div>

              {useKmeans && (
                <div>
                  <label className="text-xs text-gray-500">Number of Colors</label>
                  <input
                    type="number"
                    min="2"
                    max="256"
                    value={kmeansColors}
                    onChange={(e) => setKmeansColors(Number(e.target.value))}
                    className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm"
                  />
                  <p className="text-xs text-gray-500 mt-1">Reduces image to N dominant colors before applying palette/dithering.</p>

                  {generatedPalette.length > 0 && (
                    <button
                      onClick={handleSendKmeansToCustom}
                      className="w-full mt-2 px-3 py-1.5 bg-teal-700 hover:bg-teal-600 text-white text-xs font-medium rounded transition-colors"
                      title="Send K-Means palette to Geopixels Base + Custom"
                    >
                      Send Colors to Custom Palette
                    </button>
                  )}
                </div>
              )}
            </div>

            {/* Color Sampling Mask */}
            {(paletteMode === 'none' || paletteMode === 'custom') && (
              <div className="space-y-2">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={samplingMaskEnabled}
                    onChange={(e) => setSamplingMaskEnabled(e.target.checked)}
                  />
                  <span className="text-xs font-semibold text-gray-400 uppercase">Apply Sampling Mask</span>
                </label>
                {samplingMaskEnabled && (
                  <div className="space-y-2">
                    <button
                      onClick={() => setIsSamplingMaskModalOpen(true)}
                      className="w-full px-3 py-1.5 bg-indigo-700 hover:bg-indigo-600 text-white text-xs font-medium rounded transition-colors"
                    >
                      Configure Mask...
                    </button>
                    {samplingMask && (
                      <div className="text-xs text-gray-500 bg-gray-800 rounded px-2 py-1">
                        Mask active — {samplingMask.reduce((s, v) => s + (v > 0 ? 1 : 0), 0).toLocaleString()} px selected
                      </div>
                    )}
                    <p className="text-xs text-gray-500">
                      {paletteMode === 'none'
                        ? 'K-Means will only sample colors from the masked region.'
                        : 'Color suggestions will only sample from the masked region.'}
                    </p>
                  </div>
                )}
              </div>
            )}

            {/* Extra Features */}
            <div className="space-y-2 border-t border-gray-700 pt-2">
              <button
                onClick={() => setIsExtraFeaturesOpen(!isExtraFeaturesOpen)}
                className="flex items-center justify-between w-full text-xs font-semibold text-gray-400 hover:text-gray-300 uppercase"
              >
                <span>Extra Features</span>
                <span>{isExtraFeaturesOpen ? '▼' : '▶'}</span>
              </button>

              {isExtraFeaturesOpen && (
                <div className="space-y-3 pt-2">
                  <div className="border-b border-gray-700 pb-3">
                    <label className="text-xs font-semibold text-gray-400 uppercase mb-2 block">Pre-processing (Experimental)</label>
                    <select
                      value={preprocessingMethod}
                      onChange={(e) => { debounceTimeRef.current = 100; setPreprocessingMethod(e.target.value as any); }}
                      className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm mb-2"
                      title="Apply filters before pixelation to improve results (may impact performance)"
                    >
                      <option value="none">None</option>
                      <option value="kuwahara">Kuwahara (Oil Paint / Flatten)</option>
                      <option value="median">Median (De-noise / Smooth)</option>
                      <option value="bilateral">Bilateral (Soft Blur)</option>
                      <option value="edge-detect">Edge Detect (Outline Overlay)</option>
                    </select>

                    {preprocessingMethod !== 'none' && (
                      <div>
                        <div className="flex justify-between text-xs text-gray-500 mb-2">
                          <span>Intensity</span>
                          <span>{preprocessingStrength}%</span>
                        </div>
                        <input
                          type="range"
                          min="0"
                          max="100"
                          value={preprocessingStrength}
                          onChange={(e) => { debounceTimeRef.current = 100; setPreprocessingStrength(Number(e.target.value)); }}
                          className="w-full"
                        />
                        <p className="text-xs text-gray-500 mt-2">
                          {preprocessingMethod === 'bilateral' && 'Smooths surfaces while keeping edges. Good for photographs.'}
                          {preprocessingMethod === 'kuwahara' && 'Best for Pixel Art. Creates flat, "painted" clusters of color.'}
                          {preprocessingMethod === 'median' && 'Removes noise and small details. Great for cleaning up JPEGs before pixelating.'}
                          {preprocessingMethod === 'edge-detect' && 'Overlays detected edges as dark lines onto the image. Helps outlines survive downscaling.'}
                        </p>

                        {preprocessingMethod === 'edge-detect' && (
                          <div className="mt-3 space-y-2 border-t border-gray-700 pt-2">
                            <div>
                              <div className="flex justify-between text-xs text-gray-500 mb-1">
                                <span>Blurring</span>
                                <span>{edgeDetectBlur}px</span>
                              </div>
                              <input
                                type="range"
                                min="0"
                                max="10"
                                value={edgeDetectBlur}
                                onChange={(e) => { debounceTimeRef.current = 100; setEdgeDetectBlur(Number(e.target.value)); }}
                                className="w-full"
                              />
                              <p className="text-xs text-gray-600 mt-1">Pre-blur before detection. Higher = only bold edges, lower = fine detail edges.</p>
                            </div>
                            <div>
                              <label className="text-xs text-gray-500">Algorithm</label>
                              <select
                                value={edgeDetectAlgorithm}
                                onChange={(e) => { debounceTimeRef.current = 100; setEdgeDetectAlgorithm(e.target.value as any); }}
                                className="w-full bg-gray-800 border border-gray-600 rounded px-2 py-1 text-sm"
                              >
                                <option value="sobel">Sobel (General Purpose)</option>
                                <option value="scharr">Scharr (Bold Edges)</option>
                                <option value="laplacian">Laplacian (Thin Lines)</option>
                              </select>
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                  <div>
                    <div className="flex justify-between text-xs text-gray-500">
                      <span>Brightness</span>
                      <div className="flex items-center gap-2">
                        <span>{brightness}</span>
                        <button
                          onClick={() => setBrightness(0)}
                          className="text-gray-500 hover:text-white disabled:opacity-0 transition-opacity"
                          title="Reset Brightness"
                          disabled={brightness === 0}
                        >
                          ↺
                        </button>
                      </div>
                    </div>
                    <input
                      type="range"
                      min="-100"
                      max="100"
                      value={brightness}
                      onChange={(e) => setBrightness(Number(e.target.value))}
                      className="w-full"
                    />
                  </div>
                  <div>
                    <div className="flex justify-between text-xs text-gray-500">
                      <span>Contrast</span>
                      <div className="flex items-center gap-2">
                        <span>{contrast}</span>
                        <button
                          onClick={() => setContrast(0)}
                          className="text-gray-500 hover:text-white disabled:opacity-0 transition-opacity"
                          title="Reset Contrast"
                          disabled={contrast === 0}
                        >
                          ↺
                        </button>
                      </div>
                    </div>
                    <input
                      type="range"
                      min="-100"
                      max="100"
                      value={contrast}
                      onChange={(e) => setContrast(Number(e.target.value))}
                      className="w-full"
                    />
                  </div>
                  <div>
                    <div className="flex justify-between text-xs text-gray-500">
                      <span>Saturation</span>
                      <div className="flex items-center gap-2">
                        <span>{saturation}</span>
                        <button
                          onClick={() => setSaturation(0)}
                          className="text-gray-500 hover:text-white disabled:opacity-0 transition-opacity"
                          title="Reset Saturation"
                          disabled={saturation === 0}
                        >
                          ↺
                        </button>
                      </div>
                    </div>
                    <input
                      type="range"
                      min="-100"
                      max="100"
                      value={saturation}
                      onChange={(e) => setSaturation(Number(e.target.value))}
                      className="w-full"
                    />
                  </div>
                  <div className="border-t border-gray-700 pt-3">
                    <div className="flex justify-between text-xs text-gray-500">
                      <span>Preserve Detail</span>
                      <div className="flex items-center gap-2">
                        <span>ΔE≤{preserveDetailThreshold.toFixed(1)}</span>
                        <button
                          onClick={() => setPreserveDetailThreshold(0)}
                          className="text-gray-500 hover:text-white disabled:opacity-0 transition-opacity"
                          title="Reset Preserve Detail"
                          disabled={preserveDetailThreshold === 0}
                        >
                          ↺
                        </button>
                      </div>
                    </div>
                    <input
                      type="range"
                      min="0"
                      max="5"
                      step="0.1"
                      value={preserveDetailThreshold}
                      onChange={(e) => { debounceTimeRef.current = 100; setPreserveDetailThreshold(Number(e.target.value)); }}
                      className="w-full"
                    />
                    <p className="text-xs text-gray-500 mt-1">
                      Pixels within this ΔE threshold keep their original color instead of snapping to palette. Higher = more detail preserved.
                    </p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Execute button - sticky footer */}
          {!autoUpdate && (
            <div className="p-4 border-t border-gray-700 bg-gray-800/30 flex-shrink-0">
              <button
                onClick={processImage}
                className="w-full bg-green-600 hover:bg-green-500 text-white py-2 rounded font-semibold transition-colors flex items-center justify-center gap-2"
              >
                <span>▶</span>
                <span>Execute</span>
              </button>
            </div>
          )}

        </div>

        {/* Right: Preview */}
        <div className="flex-1 bg-gray-900 relative overflow-hidden flex flex-col">
          {/* Zoom Controls */}
          <div className="flex items-center justify-between px-4 py-3 bg-gray-800/50 border-b border-gray-700 flex-shrink-0">
            <div className="flex items-center gap-3">
              <span className="text-xs text-gray-400">Preview</span>
              <label className="flex items-center gap-1 cursor-pointer">
                <input
                  type="checkbox"
                  checked={autoUpdate}
                  onChange={(e) => setAutoUpdate(e.target.checked)}
                  className="rounded border-gray-600 bg-gray-700 text-blue-600 focus:ring-blue-500 focus:ring-offset-gray-800"
                />
                <span className="text-xs text-gray-400 select-none">Auto-update</span>
              </label>
              <label className="flex items-center gap-1 cursor-pointer" title="Always fit preview to screen">
                <input
                  type="checkbox"
                  checked={pinFitToScreen}
                  onChange={(e) => setPinFitToScreen(e.target.checked)}
                  className="rounded border-gray-600 bg-gray-700 text-blue-600 focus:ring-blue-500 focus:ring-offset-gray-800"
                />
                <span className="text-xs text-gray-400 select-none">Pin Fit</span>
              </label>
              {/* Before/After quick buttons */}
              <div className="flex items-center gap-1 ml-2 border-l border-gray-700 pl-2">
                <button
                  onClick={() => setComparePosition(0)}
                  className="bg-gray-700 px-1.5 py-0.5 rounded hover:bg-gray-600 text-xs text-gray-300"
                  title="Show original (before)"
                >
                  ◀ Before
                </button>
                <button
                  onClick={() => setComparePosition(100)}
                  className="bg-gray-700 px-1.5 py-0.5 rounded hover:bg-gray-600 text-xs text-gray-300"
                  title="Show pixelated (after)"
                >
                  After ▶
                </button>
              </div>
            </div>
            <div className="flex space-x-2 items-center">
              <button onClick={handleZoomOut} className="bg-gray-700 p-1 rounded hover:bg-gray-600 text-sm font-bold" title="Zoom out">−</button>
              <span className="bg-gray-700 px-2 py-1 rounded text-sm font-mono min-w-[50px] text-center">{Math.round(zoom * 100)}%</span>
              <button onClick={handleZoomIn} className="bg-gray-700 p-1 rounded hover:bg-gray-600 text-sm font-bold" title="Zoom in">+</button>
              <button onClick={handleFitToScreen} className="bg-gray-700 px-2 py-1 rounded hover:bg-gray-600 text-xs" title="Fit to screen">Fit</button>
              <button onClick={handleZoomReset} className="bg-gray-700 px-2 py-1 rounded hover:bg-gray-600 text-xs" title="Reset zoom">Reset</button>
              <button onClick={handleResetSettings} className="bg-gray-700 px-2 py-1 rounded hover:bg-gray-600 text-xs text-yellow-400" title="Reset all pixelator settings to defaults">⟳ Settings</button>
              <button onClick={() => setIsPresetsModalOpen(true)} className="bg-gray-700 px-2 py-1 rounded hover:bg-gray-600 text-xs text-blue-400" title="Save/load pixelation profiles">Profiles...</button>
            </div>
          </div>

          {isProcessing && (
            <div className="absolute top-14 right-4 z-20 pointer-events-none">
              <div className="bg-gray-900/90 border border-gray-700 text-gray-200 text-xs px-3 py-1.5 rounded shadow-lg flex items-center gap-2">
                <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></div>
                Generating...
              </div>
            </div>
          )}

          <div
            ref={previewContainerRef}
            className="flex-1 overflow-auto bg-gray-900"
          >
            {previewImage ? (
              <div
                style={{
                  display: 'inline-block',
                  padding: '20px',
                }}
              >
                {/* Before/After comparison container */}
                <div
                  ref={compareContainerRef}
                  className="relative select-none"
                  style={{
                    width: imageDimensions ? `${imageDimensions.width * zoom}px` : 'auto',
                    height: imageDimensions ? `${imageDimensions.height * zoom}px` : 'auto',
                    cursor: isDraggingCompare.current ? 'ew-resize' : undefined,
                  }}
                  onMouseDown={(e) => {
                    // Allow click-to-position on the container
                    if (e.target === compareContainerRef.current || (e.target as HTMLElement).closest('[data-compare-area]')) {
                      isDraggingCompare.current = true;
                      handleCompareMove(e.clientX);
                    }
                  }}
                >
                  {/* Original image (behind, clipped to right side only) */}
                  {comparePosition < 100 && (
                    <img
                      ref={originalImgRef}
                      src={layer.imageData}
                      alt="Original"
                      draggable={false}
                      data-compare-area
                      style={{
                        position: 'absolute',
                        top: 0,
                        left: 0,
                        width: '100%',
                        height: '100%',
                        objectFit: 'fill',
                        imageRendering: 'pixelated',
                        pointerEvents: 'none',
                        clipPath: `polygon(${comparePosition}% 0, 100% 0, 100% 100%, ${comparePosition}% 100%)`,
                      }}
                    />
                  )}
                  {/* Pixelated image (on top, clipped) */}
                  <img
                    ref={imgRef}
                    src={previewImage}
                    alt="Preview"
                    draggable={false}
                    onLoad={handleImageLoad}
                    data-compare-area
                    style={{
                      position: 'relative',
                      width: '100%',
                      height: '100%',
                      maxWidth: 'none',
                      imageRendering: 'pixelated',
                      clipPath: `polygon(0 0, ${comparePosition}% 0, ${comparePosition}% 100%, 0 100%)`,
                      pointerEvents: 'none',
                    }}
                  />
                  {/* Color highlight overlay */}
                  <canvas
                    ref={highlightCanvasRef}
                    style={{
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      width: '100%',
                      height: '100%',
                      imageRendering: 'pixelated',
                      pointerEvents: 'none',
                      clipPath: `polygon(0 0, ${comparePosition}% 0, ${comparePosition}% 100%, 0 100%)`,
                      opacity: highlightColor ? 1 : 0,
                      transition: 'opacity 100ms',
                    }}
                  />
                  {/* Slider divider line */}
                  {comparePosition > 0 && comparePosition < 100 && (
                    <div
                      style={{
                        position: 'absolute',
                        top: 0,
                        left: `${comparePosition}%`,
                        transform: 'translateX(-50%)',
                        width: '2px',
                        height: '100%',
                        background: 'white',
                        boxShadow: '0 0 4px rgba(0,0,0,0.7)',
                        cursor: 'ew-resize',
                        zIndex: 10,
                      }}
                      onMouseDown={handleCompareMouseDown}
                    >
                      {/* Slider handle */}
                      <div
                        style={{
                          position: 'absolute',
                          top: '50%',
                          left: '50%',
                          transform: 'translate(-50%, -50%)',
                          width: '24px',
                          height: '24px',
                          background: 'white',
                          borderRadius: '50%',
                          boxShadow: '0 0 6px rgba(0,0,0,0.5)',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          cursor: 'ew-resize',
                        }}
                      >
                        <span style={{ fontSize: '10px', color: '#333', fontWeight: 'bold', userSelect: 'none' }}>⟷</span>
                      </div>
                    </div>
                  )}
                  {/* Labels */}
                  {comparePosition > 5 && comparePosition < 95 && (
                    <>
                      <div
                        className="absolute top-2 left-2 bg-black/60 text-white text-[10px] px-1.5 py-0.5 rounded pointer-events-none"
                        style={{ zIndex: 11 }}
                      >
                        After
                      </div>
                      <div
                        className="absolute top-2 right-2 bg-black/60 text-white text-[10px] px-1.5 py-0.5 rounded pointer-events-none"
                        style={{ zIndex: 11 }}
                      >
                        Before
                      </div>
                    </>
                  )}
                </div>
              </div>
            ) : (
              <div className="absolute inset-0 flex items-center justify-center text-gray-500">
                Click Execute to generate preview
              </div>
            )}
          </div>

          {/* Apply Button - Bottom Right */}
          <div className="px-4 py-3 bg-gray-800/50 border-t border-gray-700 flex-shrink-0">
            <button
              onClick={handleApply}
              disabled={!previewImage}
              className="w-full bg-blue-600 hover:bg-blue-500 disabled:bg-gray-600 disabled:cursor-not-allowed text-white py-2 rounded font-semibold transition-colors"
            >
              Apply Pixelation
            </button>
          </div>
        </div>

        {/* Eyedropper Modal */}
        <EyedropperModal
          isOpen={isEyedropperOpen}
          onClose={() => setIsEyedropperOpen(false)}
          imageDataUrl={layer.imageData}
          onAddColors={handleEyedropperColors}
        />

        {/* GeoPixels Palette Modal */}
        <GeoPixelsPaletteModal
          isOpen={isGeoPixelsPaletteOpen}
          onClose={() => setIsGeoPixelsPaletteOpen(false)}
          onAddColors={handleGeoPixelsColors}
        />

        {/* Gradient Picker Modal */}
        <GradientPickerModal
          isOpen={isGradientPickerOpen}
          onClose={() => setIsGradientPickerOpen(false)}
          imageDataUrl={layer.imageData}
          onAddColors={handleEyedropperColors}
        />

        {/* Group Noise Modal */}
        <GroupNoiseModal
          isOpen={isGroupNoiseOpen}
          onClose={() => setIsGroupNoiseOpen(false)}
          palette={getPalette()}
          onApply={(reduced) => {
            setCustomPaletteInput(reduced.join(', '));
            if (paletteMode !== 'custom') setPaletteMode('custom');
          }}
        />

        {/* Sampling Mask Modal */}
        <SamplingMaskModal
          isOpen={isSamplingMaskModalOpen}
          onClose={() => setIsSamplingMaskModalOpen(false)}
          imageData={layer.imageData}
          existingMask={samplingMask}
          onApply={(mask, w, h) => {
            setSamplingMask(mask);
            setSamplingMaskDims({ w, h });
          }}
        />

        {/* Presets Modal */}
        {isPresetsModalOpen && (
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50" onClick={() => setIsPresetsModalOpen(false)}>
            <div className="bg-gray-800 border border-gray-600 rounded-lg shadow-xl w-96 max-h-[80vh] flex flex-col" onClick={(e) => e.stopPropagation()}>
              <div className="flex items-center justify-between px-4 py-3 border-b border-gray-700">
                <h3 className="text-sm font-semibold text-gray-200">Pixelation Presets</h3>
                <button onClick={() => setIsPresetsModalOpen(false)} className="text-gray-400 hover:text-white text-lg">×</button>
              </div>

              {/* Save new preset */}
              <div className="px-4 py-3 border-b border-gray-700 flex gap-2">
                <input
                  type="text"
                  placeholder="Preset name..."
                  value={presetName}
                  onChange={(e) => setPresetName(e.target.value)}
                  onKeyDown={(e) => { if (e.key === 'Enter') savePreset(presetName); }}
                  className="flex-1 bg-gray-900 border border-gray-600 rounded px-2 py-1.5 text-sm text-gray-200"
                />
                <button
                  onClick={() => savePreset(presetName)}
                  disabled={!presetName.trim()}
                  className="px-3 py-1.5 bg-blue-600 hover:bg-blue-500 disabled:bg-gray-600 disabled:cursor-not-allowed text-white text-xs font-medium rounded transition-colors"
                >
                  Save Current
                </button>
              </div>

              {/* Preset list */}
              <div className="flex-1 overflow-y-auto p-2 space-y-1">
                {presets.length === 0 ? (
                  <div className="text-center text-sm text-gray-500 py-8">No presets saved yet</div>
                ) : (
                  presets.map((preset, idx) => (
                    <div key={idx} className="flex items-center gap-1 bg-gray-900 rounded p-2 group">
                      <div className="flex-1 min-w-0">
                        <div className="text-sm text-gray-200 truncate">{preset.name}</div>
                        <div className="text-xs text-gray-500 truncate">
                          {preset.settings.paletteMode} · {preset.settings.targetHeight}px · {preset.settings.resamplingMethod}
                        </div>
                      </div>
                      <button
                        onClick={() => loadPreset(preset.settings)}
                        className="px-2 py-1 bg-blue-600 hover:bg-blue-500 text-white text-xs rounded transition-colors flex-shrink-0"
                      >
                        Load
                      </button>
                      <button
                        onClick={() => movePreset(idx, 'up')}
                        disabled={idx === 0}
                        className="px-1.5 py-1 bg-gray-700 hover:bg-gray-600 text-gray-400 text-xs rounded transition-colors disabled:opacity-30 flex-shrink-0"
                      >
                        ↑
                      </button>
                      <button
                        onClick={() => movePreset(idx, 'down')}
                        disabled={idx === presets.length - 1}
                        className="px-1.5 py-1 bg-gray-700 hover:bg-gray-600 text-gray-400 text-xs rounded transition-colors disabled:opacity-30 flex-shrink-0"
                      >
                        ↓
                      </button>
                      <button
                        onClick={() => deletePreset(idx)}
                        className="px-1.5 py-1 bg-red-800 hover:bg-red-700 text-red-300 text-xs rounded transition-colors flex-shrink-0"
                      >
                        ×
                      </button>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    )} />
  );
};

export default PixelatorModal;
